import{_ as t,o as i,c as r,a0 as a}from"./chunks/framework.B3sz4m_N.js";const u=JSON.parse('{"title":"AI-Augmented Development Pipelines (Reconciled)","description":"Reconciled plan for CI + Bionic PR bot + Cursor — guardrails, 90-day pilot, KPIs, and risks for WordPress and Laravel teams.","frontmatter":{"title":"AI-Augmented Development Pipelines (Reconciled)","description":"Reconciled plan for CI + Bionic PR bot + Cursor — guardrails, 90-day pilot, KPIs, and risks for WordPress and Laravel teams."},"headers":[],"relativePath":"reports/ai-augmented-dev-pipeline/index.md","filePath":"reports/ai-augmented-dev-pipeline/index.md"}'),o={name:"reports/ai-augmented-dev-pipeline/index.md"};function n(s,e,d,p,l,c){return i(),r("div",null,[...e[0]||(e[0]=[a('<p>This report is the <strong>reconciled</strong> output from multi-agent review of AI-augmented development pipelines. It defines a single implementable plan: Option A (CI + Bionic + team Cursor subscription) with guardrails, governance, a 90-day roadmap, KPIs, and risk register. <strong>Cursor is a team-based subscription with limits</strong> (fixed cost or cap per seat); the £200/£500 budget ceiling applies to Bionic and other AI tools only. Cursor rate limits follow the subscription plan; hitting plan limits is a usage/availability matter, not a cost breach.</p><h2 id="report-sections" tabindex="-1">Report sections <a class="header-anchor" href="#report-sections" aria-label="Permalink to &quot;Report sections&quot;">​</a></h2><p>Each section is available as its own page; use the sidebar to navigate.</p><table tabindex="0"><thead><tr><th>Section</th><th>Description</th></tr></thead><tbody><tr><td><a href="./reports/ai-augmented-dev-pipeline/01-overview.html">1. Overview</a></td><td>Problem context, architecture, tooling, guardrails, KPIs, next steps</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/02-pr-review.html">2. PR Review (AI-Augmented)</a></td><td>First-pass PR review with Bionic — diff-only, no merge rights</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/03-refactoring.html">3. Refactoring (AI-Assisted)</a></td><td>Rector in CI, Cursor locally — PHP 8.x and WP/Laravel refactors</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/04-migration-intelligence.html">4. Migration Intelligence</a></td><td>Impact analysis, runbooks, ordered execution for PHP and WP upgrades</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/05-test-generation.html">5. Test Generation (AI-Assisted)</a></td><td>PHPUnit/Pest suggestions via Cursor — human review and ownership</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/06-documentation.html">6. Documentation (AI-Assisted)</a></td><td>README, runbooks, API docs — Cursor drafts, human approval</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/07-tooling-comparison.html">7. Tooling Comparison (OSS vs SaaS)</a></td><td>Bionic + team Cursor; budget for Bionic/other; no AI in CI</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/08-governance-and-controls.html">8. Governance and Controls</a></td><td>UK GDPR, redaction, client approval, safe deployment checklist</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/09-90-day-roadmap.html">9. 90-Day Roadmap</a></td><td>Pilot phases 0–30, 30–60, 60–90 — milestones and success criteria</td></tr><tr><td><a href="./reports/ai-augmented-dev-pipeline/10-kpis-and-risks.html">10. KPIs and Risks</a></td><td>Quantifiable KPIs, risk register, stop conditions, next actions</td></tr></tbody></table><p>The report is structured so it can be read section by section from the sidebar or as a linked set of pages. Source: <code>research/initiatives/2026-02-23_ai-augmented-dev-pipeline-RECONCILED.md</code>.</p><p><strong>Hero images:</strong> Pencil-drawn section header concepts (one per section) are specified in <a href="./hero-image-concepts.html">Hero image concepts</a> for illustration or image-generation use.</p>',6)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
